<?php
 namespace FilesManager; class Uploader { use Traits\Loggable; use Traits\Validatable; private string $basePath; private int $maxFileSize; private array $allowedExtensions; private array $allowedMimes; public function __construct( string $basePath, int $maxFileSize = 10485760, array $allowedExtensions = [], array $allowedMimes = [] ) { $this->basePath = realpath($basePath); $this->maxFileSize = $maxFileSize; $this->allowedExtensions = array_map('strtolower', $allowedExtensions); $this->allowedMimes = $allowedMimes; if ($this->basePath === false || !is_dir($this->basePath)) { throw new \Exception('Base path inválido'); } } public function upload(array $file, string $targetPath = '/', ?string $conflictAction = null): array { if (!isset($file['error']) || is_array($file['error'])) { throw new \Exception('Parâmetros inválidos'); } switch ($file['error']) { case UPLOAD_ERR_OK: break; case UPLOAD_ERR_INI_SIZE: case UPLOAD_ERR_FORM_SIZE: throw new \Exception('Arquivo muito grande'); case UPLOAD_ERR_NO_FILE: throw new \Exception('Nenhum arquivo enviado'); default: throw new \Exception('Erro desconhecido ao fazer upload'); } if (!Validator::validateFileSize($file['size'], $this->maxFileSize)) { throw new \Exception(sprintf( 'Arquivo muito grande. Máximo: %s', $this->formatBytes($this->maxFileSize) )); } $fileName = $this->sanitizeFilename(basename($file['name'])); if (!Validator::validateFileName($fileName)) { throw new \Exception('Nome de arquivo inválido'); } if (!$this->validateFileExtension($fileName, $this->allowedExtensions)) { throw new \Exception(sprintf( 'Extensão não permitida. Permitidas: %s', implode(', ', $this->allowedExtensions) )); } if (!$this->validateMimeType($file['tmp_name'], $this->allowedMimes)) { throw new \Exception('Tipo de arquivo não permitido'); } $fullTargetPath = $this->validatePath($targetPath, $this->basePath); if ($fullTargetPath === false || !is_dir($fullTargetPath)) { throw new \Exception('Caminho de destino inválido'); } $destination = $fullTargetPath . '/' . $fileName; if (file_exists($destination)) { if ($conflictAction === 'rename') { $counter = 1; while (file_exists($destination)) { $pathInfo = pathinfo($fileName); $newName = $pathInfo['filename'] . '_' . $counter; if (isset($pathInfo['extension'])) { $newName .= '.' . $pathInfo['extension']; } $destination = $fullTargetPath . '/' . $newName; $counter++; } } elseif ($conflictAction === 'replace') { } else { throw new \Exception('Arquivo já existe'); } } if (!move_uploaded_file($file['tmp_name'], $destination)) { throw new \Exception('Falha ao mover arquivo'); } chmod($destination, 0644); return [ 'name' => basename($destination), 'path' => str_replace($this->basePath, '', $destination), 'size' => filesize($destination), 'type' => mime_content_type($destination), 'uploaded' => time(), ]; } public function uploadMultiple(array $files, string $targetPath = '/', ?string $conflictAction = null): array { $results = []; foreach ($files as $file) { try { $results[] = [ 'success' => true, 'file' => $this->upload($file, $targetPath, $conflictAction), ]; } catch (\Exception $e) { $results[] = [ 'success' => false, 'error' => $e->getMessage(), 'filename' => $file['name'] ?? 'unknown', ]; } } return $results; } private function formatBytes(int $bytes): string { if ($bytes === 0) { return '0 Bytes'; } $k = 1024; $sizes = ['Bytes', 'KB', 'MB', 'GB']; $i = floor(log($bytes) / log($k)); return round($bytes / pow($k, $i), 2) . ' ' . $sizes[$i]; } } 